  try {
    const raw = fs.readFileSync(filePath, 'utf8');
    const parsed = JSON.parse(raw);
    if (typeof parsed.pid === 'number') return parsed;
  } catch {
    // Missing or corrupt lease files are treated as no active lease.
  }
  return null;
}

function readOwnerLeaseFile(filePath = ownerLeasePath()) {
  try {
    const parsed = JSON.parse(fs.readFileSync(filePath, 'utf8'));
    if (
      Number.isInteger(parsed.ownerPid) &&
      Number.isInteger(parsed.ppid) &&
      typeof parsed.executablePath === 'string' &&
      typeof parsed.startedAtIso === 'string' &&
      typeof parsed.lastHeartbeatIso === 'string' &&
      Number.isInteger(parsed.ttlMs) &&
      typeof parsed.canonicalDbDir === 'string'
    ) {
      return parsed;
    }
  } catch {
    // Missing or corrupt owner leases are treated as no active owner.
  }
  return null;
}

function readOwnerLeaseSnapshot(filePath = ownerLeasePath()) {
  try {
    const raw = fs.readFileSync(filePath, 'utf8');
    const parsed = JSON.parse(raw);
    if (
      Number.isInteger(parsed.ownerPid) &&
      Number.isInteger(parsed.ppid) &&
      typeof parsed.executablePath === 'string' &&
      typeof parsed.startedAtIso === 'string' &&
      typeof parsed.lastHeartbeatIso === 'string' &&
      Number.isInteger(parsed.ttlMs) &&
      typeof parsed.canonicalDbDir === 'string'
    ) {
      return {
        lease: parsed,
        mtimeMs: fs.statSync(filePath).mtimeMs,
        contentHash: createHash('sha256').update(raw).digest('hex'),
      };
    }
  } catch {
    // Missing or corrupt owner leases are treated as no active owner.
  }
  return null;
}

function staleLeaseUnchanged(snapshot, current) {
  return Boolean(
    snapshot &&
    current &&
    snapshot.lease.ownerPid === current.lease.ownerPid &&
    snapshot.mtimeMs === current.mtimeMs &&
    snapshot.contentHash === current.contentHash,
  );
}

function writeOwnerLeaseFile(lease) {
  const currentLeasePath = path.join(ensureCanonicalDir(path.dirname(ownerLeasePath())), OWNER_LEASE_FILE_NAME);
  const tmp = `${currentLeasePath}.tmp.${process.pid}.${Date.now()}.${Math.random().toString(36).slice(2)}`;
  fs.writeFileSync(tmp, `${JSON.stringify(lease, null, 2)}\n`, { mode: 0o600, flag: 'wx' });
  fs.renameSync(tmp, currentLeasePath);
}

function writeOwnerLeaseFileExclusive(lease) {
  const currentLeasePath = path.join(ensureCanonicalDir(path.dirname(ownerLeasePath())), OWNER_LEASE_FILE_NAME);
  let fd;
  try {
    fd = fs.openSync(currentLeasePath, 'wx', 0o600);
    fs.writeFileSync(fd, `${JSON.stringify(lease, null, 2)}\n`, 'utf8');
    fs.fsyncSync(fd);
    return true;
  } catch (error) {
    if (error.code === 'EEXIST') return false;
    throw error;
  } finally {
    if (typeof fd === 'number') fs.closeSync(fd);
  }
}

function writeDaemonPidRegistry(registry) {
  const currentRegistryPath = path.join(
    ensureCanonicalDir(path.dirname(daemonPidRegistryPath(registry.canonicalDbDir ?? resolvedDbDir()))),
    DAEMON_PID_REGISTRY_FILE_NAME,
  );
  const tmp = `${currentRegistryPath}.tmp.${process.pid}.${Date.now()}.${Math.random().toString(36).slice(2)}`;
  try {
    fs.writeFileSync(tmp, `${JSON.stringify(registry, null, 2)}\n`, { mode: 0o600, flag: 'wx' });
    fs.renameSync(tmp, currentRegistryPath);
  } catch (error) {
    try {
      fs.rmSync(tmp, { force: true });
    } catch {
      // Best-effort temp cleanup.
    }
    throw error;
  }
}

function discoverDaemonFromRegistry(registryDbDir = resolvedDbDir()) {
  try {
    const canonicalRegistryDbDir = canonicalizePath(registryDbDir);
    const registryPath = daemonPidRegistryPath(canonicalRegistryDbDir);
    const parsed = JSON.parse(fs.readFileSync(registryPath, 'utf8'));
    if (
      Number.isInteger(parsed.daemonPid) &&
      parsed.daemonPid > 0 &&
      Number.isInteger(parsed.launcherPid) &&
      parsed.launcherPid > 0 &&
      typeof parsed.startedAtIso === 'string' &&
      typeof parsed.canonicalDbDir === 'string' &&
      parsed.canonicalDbDir === canonicalRegistryDbDir &&
      (typeof parsed.socketPath === 'string' || parsed.socketPath === null)
    ) {
      return {
        daemonPid: parsed.daemonPid,
        launcherPid: parsed.launcherPid,
        socketPath: parsed.socketPath,
        startedAtIso: parsed.startedAtIso,
        canonicalDbDir: parsed.canonicalDbDir,
        registryPath,
      };
    }
  } catch {
    // Missing or corrupt registry files are not authoritative.
  }
  return null;
}

function clearDaemonPidRegistry(registryDbDir = resolvedDbDir()) {
  try {
    fs.unlinkSync(daemonPidRegistryPath(registryDbDir));
  } catch (error) {
    if (error.code !== 'ENOENT') throw error;
  }
}

// The socket path this owner's environment computes. Recording it in the
// leases lets a secondary under a divergent SPECKIT_IPC_SOCKET_DIR bridge
// to the REAL socket instead of probing a recomputed wrong one and
// misreporting a healthy owner as no-bridge-socket.
function ownerSocketPath() {
  try {
    const { getIpcSocketPath } = loadBridgeModule();
    if (typeof getIpcSocketPath !== 'function') return null;
    return getIpcSocketPath('mk-code-index', { dbDir: resolvedDbDir() }) ?? null;
  } catch {
    return null;
  }
}

let ownerLeaseHeartbeatTimer = null;

function clearOwnerLeaseHeartbeat() {
  if (ownerLeaseHeartbeatTimer) {
    clearInterval(ownerLeaseHeartbeatTimer);
    ownerLeaseHeartbeatTimer = null;
  }
}

// Without a periodic refresh, every healthy long-running owner classifies
// as stale-heartbeat-reclaim about two minutes after spawn, so each later
// secondary start rewrites the owner lease before rediscovering the live
// PID lease — churn plus reclaim-race exposure for nothing.
function startOwnerLeaseHeartbeat(ownerPid) {
  clearOwnerLeaseHeartbeat();
  const lease = readOwnerLeaseFile();
  const ttlMs = Number.isFinite(lease?.ttlMs) && lease.ttlMs > 0 ? lease.ttlMs : 60000;
  const intervalMs = Math.max(1000, Math.floor(ttlMs / 2));
  ownerLeaseHeartbeatTimer = setInterval(() => {
    if (refreshOwnerLeaseFile(ownerPid)) return;
    // A failed refresh means a concurrent reclaim superseded this owner;
    // this launcher exits with its child rather than supervising relaunches,
    // so stop heartbeating instead of fighting the new owner.
    log('owner lease heartbeat refresh failed (superseded); stopping heartbeat');
    clearOwnerLeaseHeartbeat();
  }, intervalMs);
  ownerLeaseHeartbeatTimer.unref?.();
}

function buildOwnerLease(ownerPid = process.pid) {
  return {
    ownerPid,
    ppid: process.ppid,
    executablePath: process.execPath,
    startedAtIso: new Date().toISOString(),
    lastHeartbeatIso: new Date().toISOString(),
    ttlMs: 60000,
    canonicalDbDir: resolvedDbDir(),
    socketPath: ownerSocketPath(),
  };
}

function processLiveness(pid) {
  if (!Number.isInteger(pid) || pid <= 0) return 'dead';
  try {
    process.kill(pid, 0);
    return 'alive';
  } catch (error) {
    if (error.code === 'ESRCH') return 'dead';
    if (error.code === 'EPERM') return 'unknown-eperm';
    return 'alive';
  }
}

function classifyOwnerReclaim(input) {
  const {
    pidAlive,
    socketServing,
    childSpawnedAtMs,
    heartbeatAgeMs,
    nowMs,
    graceMs,
    maxInitMs,
    heartbeatTtlMs,
  } = input;

  if (!pidAlive) return 'dead-pid';
  if (socketServing) return 'serving';
  if (childSpawnedAtMs === null) return 'recheck';

  const childAgeMs = nowMs - childSpawnedAtMs;
  if (childAgeMs <= graceMs) return 'still-starting';
  if (childAgeMs <= maxInitMs) return 'recheck';
  if (heartbeatAgeMs !== null && heartbeatAgeMs > heartbeatTtlMs) return 'reclaimable';
  return 'recheck';
}

function ownerUidMatches({ leasePath: targetLeasePath, recordedUid, currentUid, statUid }) {
  if (!Number.isInteger(currentUid)) return false;
  const ownerUid = recordedUid !== undefined && recordedUid !== null
    ? recordedUid
    : typeof statUid === 'function'
      ? statUid(targetLeasePath)
      : null;
  return Number.isInteger(ownerUid) && ownerUid === currentUid;
}

function cmdlineBasename(cmdline) {
  const command = String(cmdline).split('\0')[0].trim().split(/\s+/)[0];
  return command ? path.basename(command) : '';
}

function verifyPidIdentity({ pid, recordedCmdlineBasename, recordedStartMs, toleranceMs, lookups }) {
  const liveCmdline = lookups.readCmdline(pid);
  if (liveCmdline === null) return { ok: false, reason: 'no-process' };
  if (cmdlineBasename(liveCmdline) !== recordedCmdlineBasename) {
    return { ok: false, reason: 'cmdline-mismatch' };
  }

  const liveStartMs = lookups.readStartMs(pid);
  if (!Number.isFinite(liveStartMs) || Math.abs(liveStartMs - recordedStartMs) > toleranceMs) {
    return { ok: false, reason: 'start-time-mismatch' };
  }
  return { ok: true, reason: 'match' };
}

function readProcessCmdline(pid) {
  if (!Number.isInteger(pid) || pid <= 0) return null;
  if (process.platform === 'linux') {
    try {
      return fs.readFileSync(`/proc/${pid}/cmdline`, 'utf8');
    } catch {
      return null;
    }
  }
  const result = spawnSync('ps', ['-p', String(pid), '-o', 'command='], {
    encoding: 'utf8',
    stdio: ['ignore', 'pipe', 'ignore'],
  });
  if (result.status !== 0 || !result.stdout) return null;
  return result.stdout.trim();
}

function readProcessStartMs(pid) {
  if (!Number.isInteger(pid) || pid <= 0) return null;
  const result = spawnSync('ps', ['-p', String(pid), '-o', 'lstart='], {
    encoding: 'utf8',
    stdio: ['ignore', 'pipe', 'ignore'],
  });
  if (result.status !== 0 || !result.stdout) return null;
  const parsed = Date.parse(result.stdout.trim());
  return Number.isFinite(parsed) ? parsed : null;
}

function parseIsoMs(value) {
  if (typeof value !== 'string' || value.length === 0) return null;
  const parsed = Date.parse(value);
  return Number.isFinite(parsed) ? parsed : null;
}

function ageSinceIsoMs(value, nowMs = Date.now()) {
  const parsed = parseIsoMs(value);
  return parsed === null ? null : nowMs - parsed;
}

function readParentPid(pid) {
  if (!Number.isInteger(pid) || pid <= 0) return null;
  if (process.platform === 'linux') {
    try {
      const status = fs.readFileSync(`/proc/${pid}/status`, 'utf8');
      const match = status.match(/^PPid:\s+(\d+)$/m);
      return match ? Number.parseInt(match[1], 10) : null;
    } catch {
      return null;
    }
  }
  const result = spawnSync('ps', ['-o', 'ppid=', '-p', String(pid)], {
    encoding: 'utf8',
    stdio: ['ignore', 'pipe', 'ignore'],
  });
  if (result.status !== 0 || !result.stdout) return null;
  const parsed = Number.parseInt(result.stdout.trim(), 10);
  return Number.isInteger(parsed) ? parsed : null;
}

function classifyOwnerLease(lease) {
  const liveness = processLiveness(lease.ownerPid);
  if (liveness === 'dead') return 'stale-pid';
  if (liveness === 'unknown-eperm') return 'unknown-eperm';

  const actualPpid = readParentPid(lease.ownerPid);
  if (actualPpid !== null && actualPpid !== lease.ppid && actualPpid === 1) {
    return 'ppid-1-orphan';
  }

  const heartbeatMs = Date.parse(lease.lastHeartbeatIso);
  const ttlMs = Number.isFinite(lease.ttlMs) ? lease.ttlMs : 0;
  if (!Number.isFinite(heartbeatMs) || Date.now() - heartbeatMs > ttlMs * 2) {
    return 'stale-heartbeat-reclaim';
  }

  return 'live-owner';
}

function acquireOwnerLeaseFile() {
  const currentOwnerLeasePath = ownerLeasePath();
  const existingSnapshot = readOwnerLeaseSnapshot(currentOwnerLeasePath);
  const existing = existingSnapshot?.lease ?? null;

  if (existing) {
    const classification = classifyOwnerLease(existing);
    if (classification === 'live-owner' || classification === 'unknown-eperm') {
      return { acquired: false, holder: existing, classification };
    }
    log(`ownerLeaseReclaimed: ${classification} ownerPid=${existing.ownerPid}`);
  }

  const lease = buildOwnerLease(process.pid);
  // Reclaim a stale lease by removing it first, then claim exclusively (O_EXCL).
  // This collapses the fresh-acquire and stale-reclaim paths into a single CAS so
  // only one racer can win: the loser's exclusive create hits EEXIST and returns
  // acquired:false instead of last-writer-wins overwriting the winner's lease.
  if (existing) {
    const currentSnapshot = readOwnerLeaseSnapshot(currentOwnerLeasePath);
    if (!staleLeaseUnchanged(existingSnapshot, currentSnapshot)) {
      const holder = currentSnapshot?.lease ?? lease;
      launcherDiagnostic('reclaim-superseded', { ownerPid: currentSnapshot?.lease?.ownerPid ?? existing.ownerPid });
      return {
        acquired: false,
        holder,
        classification: currentSnapshot ? classifyOwnerLease(holder) : 'live-owner',
      };
    }
    try {
      fs.unlinkSync(currentOwnerLeasePath);
    } catch (error) {
      if (error.code !== 'ENOENT') throw error;
    }
  }
  if (!writeOwnerLeaseFileExclusive(lease)) {
    const holder = readOwnerLeaseFile(currentOwnerLeasePath);
    return {
      acquired: false,
      holder: holder || lease,
      classification: holder ? classifyOwnerLease(holder) : 'live-owner',
    };
  }
  ownerLeasePid = process.pid;
  if (existing) {
    emitLeaseMetric(leaseMetricClassForTransition('staleReclaimed'), {
      ownerPid: existing.ownerPid,
      ownerClassification: classifyOwnerLease(existing),
      leaseKind: 'owner',
    });
  }
  return { acquired: true, lease, reclaimed: existing };
}

function refreshOwnerLeaseFile(ownerPid, patch = {}) {
  const lease = readOwnerLeaseFile();
  if (!lease || lease.ownerPid !== ownerPid) return false;
  const nextOwnerPid = patch.ownerPid ?? ownerPid;
  writeOwnerLeaseFile({
    ...lease,
    ...patch,
    lastHeartbeatIso: new Date().toISOString(),
  });
  // Re-read after the atomic write; if a concurrent reclaim superseded us between
  // the ownership check and the write, do not claim the refresh succeeded.
  const reread = readOwnerLeaseFile();
  if (!reread || reread.ownerPid !== nextOwnerPid) return false;
  ownerLeasePid = nextOwnerPid;
  return true;
}

function clearOwnerLeaseFile() {
  if (!Number.isInteger(ownerLeasePid)) return;
  try {
    // Re-confirm ownership immediately before unlink so a successor lease written
    // after the first read is not deleted by path. A residual sub-syscall window remains; fully
    // closing it would require the launcher to share owner-lease.ts's mutation lock.
    const lease = readOwnerLeaseFile();
    if (lease && lease.ownerPid === ownerLeasePid
        && readOwnerLeaseFile()?.ownerPid === ownerLeasePid) {
      fs.unlinkSync(ownerLeasePath());
    }
  } catch {
    // Idempotent cleanup.
  } finally {
    ownerLeasePid = null;
  }
}

function clearOwnerLeaseFileIfOwner(ownerPid) {
  try {
    // Re-confirm ownership immediately before unlink (see clearOwnerLeaseFile).
    const lease = readOwnerLeaseFile();
    if (lease && lease.ownerPid === ownerPid
        && readOwnerLeaseFile()?.ownerPid === ownerPid) {
      fs.unlinkSync(ownerLeasePath());
    }
  } catch {
    // Idempotent cleanup.
  }
}

function pidLiveAt(filePath, pidField) {
  try {
    const parsed = JSON.parse(fs.readFileSync(filePath, 'utf8'));
    const pid = parsed[pidField];
    if (!Number.isInteger(pid)) return false;
    try { process.kill(pid, 0); return true; } // live
    catch (error) { return error.code === 'EPERM'; } // EPERM = exists but no perm → treat live; ESRCH = dead
  } catch { return false; } // missing/unreadable → not live
}

// A former-location DB is still "owned" if EITHER the launcher PID lease
// (.mk-code-index-launcher.json) or the owner lease (.code-graph-owner.json) names a live process.
function formerLocationOwnerLive(dir) {
  return pidLiveAt(path.join(dir, '.mk-code-index-launcher.json'), 'pid')
      || pidLiveAt(path.join(dir, '.code-graph-owner.json'), 'ownerPid');
}

function leaseHeldFromFile(filePath, legacyPath = null) {
  const lease = readLeaseFile(filePath);
  if (!lease) return { held: false, ownerPid: null, staleReclaimable: false, startedAt: null, legacyPath, socketPath: null };
  // Surface the owner-recorded socket path so the bridge prefers it over
  // recomputing one that may diverge under a different SPECKIT_IPC_SOCKET_DIR.
  const socketPath = typeof lease.socketPath === 'string' && lease.socketPath.length > 0 ? lease.socketPath : null;
  // Do not bridge to a LEGACY-location lease unless its lease file is owned by the
  // current user. A foreign-owned lease in a shared/former path could otherwise point this
  // client at a spoofed IPC socket.
  if (legacyPath && typeof process.getuid === 'function') {
    try {
      if (fs.statSync(filePath).uid !== process.getuid()) {
        return { held: false, ownerPid: null, staleReclaimable: false, startedAt: null, legacyPath, socketPath: null };
      }
    } catch {
      return { held: false, ownerPid: null, staleReclaimable: false, startedAt: null, legacyPath, socketPath: null };
    }
  }
  const startedAt = lease.startedAt ?? new Date(0).toISOString();
  try {
    process.kill(lease.pid, 0);
    return { held: true, ownerPid: lease.pid, staleReclaimable: false, startedAt, legacyPath, socketPath };
  } catch (error) {
    if (error.code === 'ESRCH') return { held: false, ownerPid: lease.pid, staleReclaimable: true, startedAt, legacyPath, socketPath };
    // Mirror skill-advisor parity — EPERM means the process exists but we lack permission (e.g. sandbox); treat as live lease.
    if (error.code === 'EPERM') return { held: true, ownerPid: lease.pid, staleReclaimable: false, startedAt, legacyPath, socketPath };
    throw error;
  }
}

function isLeaseHeld() {
  const primary = leaseHeldFromFile(leasePath());
  if (primary.held) return primary;

  for (const legacyPath of legacyLeasePaths()) {
    if (legacyPath === leasePath()) continue;
    const legacy = leaseHeldFromFile(legacyPath, legacyPath);
    if (legacy.held || legacy.staleReclaimable) return legacy;
  }

  return primary;
}

function writeLeaseHeldDiagnostic(leaseResult, suffix = '') {
  const startedAt = leaseResult.startedAt ?? new Date(0).toISOString();
  const legacyMarker = leaseResult.legacyPath ? ' (legacy path)' : '';
  process.stdout.write(`LEASE_HELD_BY:${leaseResult.ownerPid} startedAt=${startedAt}${legacyMarker}${suffix}\n`);
}

function resolveLeaseSocketPath(leaseResult) {
  if (typeof leaseResult?.socketPath === 'string' && leaseResult.socketPath.length > 0) {
    return leaseResult.socketPath;
  }
  try {
    const { getIpcSocketPath } = loadBridgeModule();
    if (typeof getIpcSocketPath !== 'function') return null;
    return getIpcSocketPath('mk-code-index', { dbDir: resolvedDbDir() }) ?? null;
  } catch {
    return null;
  }
}

async function probeLeaseSocket(socketPath) {
  if (typeof socketPath !== 'string' || socketPath.length === 0) {
    return { status: 'dead', kind: 'unknown' };
  }
  if (!fs.existsSync(socketPath)) {
    return { status: 'dead', kind: 'enoent' };
  }
  const { probeExistingService } = loadBridgeModule();
  if (typeof probeExistingService !== 'function') {
    return { status: 'dead', kind: 'unknown' };
  }
  return probeExistingService(socketPath);
}

function isSocketServing(probeResult) {
  return probeResult?.status === 'alive' && probeResult?.kind === 'json-rpc-reply';
}

async function bridgeToKnownServingSocket(socketPath, ownerPid, reason = 'serving') {
  process.stderr.write(`[mk-code-index-launcher] bridging to lease holder pid=${ownerPid} socket=${socketPath}\n`);
  await Promise.resolve(bridgeStdioThroughSessionProxy(socketPath));
  return { action: 'bridge', reason, socketPath };
}

function buildOwnerReclaimInput(ownerLease, socketServing, nowMs = Date.now()) {
  const childSpawnedAtMs = parseIsoMs(ownerLease.childSpawnedAtIso);
  const heartbeatAgeMs = ageSinceIsoMs(ownerLease.lastHeartbeatIso, nowMs);
  const heartbeatTtlMs = Number.isFinite(ownerLease.ttlMs) && ownerLease.ttlMs > 0 ? ownerLease.ttlMs : 60000;
  return {
    pidAlive: processLiveness(ownerLease.ownerPid) !== 'dead',
    socketServing,
    childSpawnedAtMs,
    heartbeatAgeMs,
    nowMs,
    graceMs: resolveStartupGraceMs(),
    maxInitMs: resolveMaxInitMs(),
    heartbeatTtlMs,
  };
}

async function classifyLiveOwnerReclaim(ownerLease, leaseResult) {
  if (!reclaimDeadSocketEnabled()) return null;
  if (!ownerLease || ownerLease.ownerPid !== leaseResult.ownerPid) return null;

  const socketPath = resolveLeaseSocketPath(leaseResult) ?? resolveLeaseSocketPath(ownerLease);
  const probe = await probeLeaseSocket(socketPath);
  const input = buildOwnerReclaimInput(ownerLease, isSocketServing(probe));
  return {
    decision: classifyOwnerReclaim(input),
    input,
    probe,
    socketPath,
  };
}

async function reportRecheckAfterProbe(leaseResult, socketPath) {
  const reprobe = await probeLeaseSocket(socketPath);
  if (isSocketServing(reprobe)) {
    return bridgeToKnownServingSocket(socketPath, leaseResult.ownerPid, 'recheck-serving');
  }
  writeLeaseHeldDiagnostic(leaseResult, ' (dead-socket-recheck)');
  return { action: 'report', reason: 'recheck', socketPath };
}

async function waitForPidExit(pid, timeoutMs) {
  const deadline = Date.now() + timeoutMs;
  while (Date.now() <= deadline) {
    if (processLiveness(pid) === 'dead') return true;
    await sleep(100);
  }
  return processLiveness(pid) === 'dead';
}

async function reapOwnerBeforeRespawn(ownerPid, options = {}) {
  const liveness = processLiveness(ownerPid);
  if (liveness === 'unknown-eperm') {
    return { allowed: false, reason: 'owner-liveness-unknown-eperm' };
  }
  if (liveness === 'dead') {
    return { allowed: true, reason: 'owner-already-dead' };
  }

  if (reclaimDeadSocketEnabled()) {
    const currentOwnerLeasePath = ownerLeasePath();
    const ownerLease = options.ownerLease ?? readOwnerLeaseFile(currentOwnerLeasePath);
    const uidMatches = ownerUidMatches({
      leasePath: currentOwnerLeasePath,
      recordedUid: ownerLease?.uid,
      currentUid: process.getuid?.(),
      statUid: (targetLeasePath) => {
        try {
          return fs.statSync(targetLeasePath).uid;
        } catch {
          return null;
        }
      },
    });
    if (!uidMatches) {
      launcherDiagnostic('foreign-owner', { ownerPid });
      return { allowed: false, reason: 'foreign-owner' };
    }

    const recordedStartMs = parseIsoMs(ownerLease?.childSpawnedAtIso ?? ownerLease?.startedAtIso);
    const identity = verifyPidIdentity({
      pid: ownerPid,
      recordedCmdlineBasename: path.basename(ownerLease?.executablePath ?? process.execPath),
      recordedStartMs,
      toleranceMs: PID_IDENTITY_START_TOLERANCE_MS,
      lookups: {
        readCmdline: readProcessCmdline,
        readStartMs: readProcessStartMs,
      },
    });
    if (!identity.ok) {
      launcherDiagnostic('pid-reuse-suspected', { ownerPid, identity: identity.reason });
      return { allowed: false, reason: 'pid-reuse-suspected' };
    }
  }

  log(`confirmed-dead socket; reaping recorded code-index owner pid ${ownerPid} before respawn`);
  try {
    process.kill(ownerPid, 'SIGTERM');
  } catch (error) {
    if (error.code !== 'ESRCH') throw error;
  }
  const exitedAfterTerm = await waitForPidExit(ownerPid, RESPAWN_REAP_GRACE_MS);
  if (!exitedAfterTerm) {
    log(`code-index owner pid ${ownerPid} exceeded ${RESPAWN_REAP_GRACE_MS}ms reap grace; sending SIGKILL`);
    try {
      process.kill(ownerPid, 'SIGKILL');
    } catch (error) {
      if (error.code !== 'ESRCH') throw error;
    }
    await waitForPidExit(ownerPid, 1000);
  }
  return { allowed: true, reason: 'owner-reaped' };
}

async function respawnAfterDeadSocket(leaseResult, decision, options = {}) {
  if (process.env.SPECKIT_BRIDGE_RESPAWN_DISABLED === '1') {
    writeLeaseHeldDiagnostic(leaseResult, ' (dead-socket-respawn-disabled)');
    return { action: 'report', reason: 'respawn-disabled', socketPath: decision.socketPath };
  }

  const ownerPid = options.respawnChildPid;
  if (!Number.isInteger(ownerPid) || ownerPid <= 0) {
    log('confirmed-dead socket but no recorded code-index child owner pid is available; respawn inert');
    writeLeaseHeldDiagnostic(leaseResult, ' (dead-socket-no-child-pid)');
    return { action: 'report', reason: 'missing-child-pid', socketPath: decision.socketPath };
  }

  let bootstrapLockHeld = false;
  try {
    bootstrapLockHeld = await acquireBootstrapLock({ requireLock: true });
    const currentOwner = readOwnerLeaseFile();
    if (currentOwner?.ownerPid !== ownerPid) {
      log('dead-socket respawn skipped; code-index owner lease changed while waiting for respawn lock');
      writeLeaseHeldDiagnostic(leaseResult, ' (dead-socket-respawn-superseded)');
      return { action: 'report', reason: 'respawn-superseded', socketPath: decision.socketPath };
    }

    if (reclaimDeadSocketEnabled()) {
      const finalProbe = await probeLeaseSocket(decision.socketPath);
      if (isSocketServing(finalProbe)) {
        launcherDiagnostic('late-serving-veto', { ownerPid, socketPath: decision.socketPath });
        return bridgeToKnownServingSocket(decision.socketPath, ownerPid, 'late-serving-veto');
      }
    }

    const reapResult = await reapOwnerBeforeRespawn(ownerPid, { ownerLease: currentOwner });
    if (!reapResult.allowed) {
      log(`dead-socket respawn skipped; ${reapResult.reason} for ownerPid=${ownerPid}`);
      writeLeaseHeldDiagnostic(leaseResult, ` (dead-socket-${reapResult.reason})`);
      return { action: 'report', reason: reapResult.reason, socketPath: decision.socketPath };
    }

    clearOwnerLeaseFileIfOwner(ownerPid);
    const lease = buildOwnerLease(process.pid);
    if (!writeOwnerLeaseFileExclusive(lease)) {
      const holder = readOwnerLeaseFile();
      log(`dead-socket respawn skipped; another launcher owns code-index owner lease pid=${holder?.ownerPid ?? 'unknown'}`);
      writeLeaseHeldDiagnostic(leaseResult, ' (dead-socket-respawn-owned)');
      return { action: 'report', reason: 'respawn-lock-held', socketPath: decision.socketPath };
    }
    ownerLeasePid = process.pid;

    buildIfNeeded([]);
    checkpointStaleWalIfNeeded(path.join(resolvedDbDir(), 'code-graph.sqlite'), { reapedOrphan: true });
    writeLeaseFile();
    launchServer();
    if (reclaimDeadSocketEnabled()) {
      launcherDiagnostic('dead-socket-reclaimed', { ownerPid, socketPath: decision.socketPath });
    }
    return { action: 'respawn', reason: 'spawned', socketPath: decision.socketPath };
  } finally {
    if (bootstrapLockHeld) {
      fs.rmSync(lockDir, { recursive: true, force: true });
    }
  }
}

async function reclaimRegisteredDaemonIfNeeded() {
  if (!reclaimDeadSocketEnabled()) return { action: 'skipped', reason: 'disabled' };
  const registry = discoverDaemonFromRegistry(resolvedDbDir());
  if (!registry) return { action: 'skipped', reason: 'missing-registry' };
  if (processLiveness(registry.daemonPid) !== 'alive') return { action: 'skipped', reason: 'pid-not-live' };

  const probe = await probeLeaseSocket(registry.socketPath);
  if (isSocketServing(probe)) return { action: 'skipped', reason: 'socket-serving', socketPath: registry.socketPath };

  let registryUid = null;
  try {
    registryUid = fs.statSync(registry.registryPath).uid;
  } catch {
    registryUid = null;
  }
  const ownerLease = {
    ownerPid: registry.daemonPid,
    ppid: registry.launcherPid,
    executablePath: process.execPath,
    startedAtIso: registry.startedAtIso,
    childSpawnedAtIso: registry.startedAtIso,
    lastHeartbeatIso: registry.startedAtIso,
    ttlMs: 60000,
    canonicalDbDir: registry.canonicalDbDir,
    socketPath: registry.socketPath,
    uid: registryUid,
  };
  const reapResult = await reapOwnerBeforeRespawn(registry.daemonPid, { ownerLease });
  if (!reapResult.allowed) {
    log(`registered orphan daemon pid ${registry.daemonPid} could not be reaped (${reapResult.reason}); not spawning a second daemon`);
    return { action: 'blocked', reason: reapResult.reason, daemonPid: registry.daemonPid, socketPath: registry.socketPath };
  }

  clearDaemonPidRegistry(path.dirname(registry.registryPath));
  log(`registered orphan daemon pid ${registry.daemonPid} reaped before spawn (${reapResult.reason})`);
  return { action: 'reaped', reason: reapResult.reason, daemonPid: registry.daemonPid, socketPath: registry.socketPath };
}

async function bridgeOrReportLeaseHeld(leaseResult, options = {}) {
  const ownerReclaim = await classifyLiveOwnerReclaim(options.ownerLease, leaseResult);
  if (ownerReclaim) {
    if (ownerReclaim.decision === 'serving') {
      return bridgeToKnownServingSocket(ownerReclaim.socketPath, leaseResult.ownerPid);
    }
    if (ownerReclaim.decision === 'still-starting') {
      const childAgeMs = ownerReclaim.input.childSpawnedAtMs === null
        ? null
        : ownerReclaim.input.nowMs - ownerReclaim.input.childSpawnedAtMs;
      launcherDiagnostic('still-starting', {
        ownerPid: leaseResult.ownerPid,
        socketPath: ownerReclaim.socketPath,
        childAgeMs,
        graceMs: ownerReclaim.input.graceMs,
      });
      writeLeaseHeldDiagnostic(leaseResult, ' (dead-socket-still-starting)');
      return { action: 'report', reason: 'still-starting', socketPath: ownerReclaim.socketPath };
    }
    if (ownerReclaim.decision === 'recheck') {
      return reportRecheckAfterProbe(leaseResult, ownerReclaim.socketPath);
    }
    if (ownerReclaim.decision === 'reclaimable') {
      const respawnResult = await respawnAfterDeadSocket(
        leaseResult,
        { action: 'respawn', reason: 'owner-reclaimable', socketPath: ownerReclaim.socketPath },
        { respawnChildPid: leaseResult.ownerPid, ownerLease: options.ownerLease },
      );
      emitLeaseMetric(
        leaseMetricClassForTransition(respawnResult.action === 'respawn' ? 'respawned' : 'heldByOther'),
        {
          ownerPid: leaseResult.ownerPid,
          reason: respawnResult.reason,
          socketPath: respawnResult.socketPath,
        },
      );
      return respawnResult;
    }
  }

  const { maybeBridgeLeaseHolder } = loadBridgeModule();
  const decision = await maybeBridgeLeaseHolder({
    serviceName: 'mk-code-index',
    leaseResult,
    loggerPrefix: 'mk-code-index-launcher',
    dbDir: resolvedDbDir(),
    bridge: bridgeStdioThroughSessionProxy,
  });
  if (decision && decision.action === 'respawn') {
    const respawnResult = await respawnAfterDeadSocket(leaseResult, decision, options);
    if (respawnResult.action === 'respawn') {
      emitLeaseMetric(leaseMetricClassForTransition('respawned'), {
        ownerPid: leaseResult.ownerPid,
        reason: respawnResult.reason,
        socketPath: respawnResult.socketPath,
      });
    } else {
      emitLeaseMetric(leaseMetricClassForTransition('heldByOther'), {
        ownerPid: leaseResult.ownerPid,
        reason: respawnResult.reason,
        socketPath: respawnResult.socketPath,
      });
    }
    return respawnResult;
  }
  emitLeaseMetric(
    leaseMetricClassForTransition(decision?.action === 'bridge' ? 'bridgedSecondary' : 'heldByOther'),
    {
      ownerPid: leaseResult.ownerPid,
      reason: decision?.reason ?? null,
      socketPath: decision?.socketPath ?? leaseResult.socketPath ?? null,
    },
  );
  return decision;
}

function writeLeaseFile() {
  const currentLeasePath = path.join(ensureCanonicalDir(path.dirname(leasePath())), PID_FILE_NAME);
  const tmp = currentLeasePath + '.tmp.' + process.pid;
  fs.writeFileSync(tmp, JSON.stringify({ pid: process.pid, startedAt: new Date().toISOString(), socketPath: ownerSocketPath() }, null, 2), { mode: 0o600 });
  fs.renameSync(tmp, currentLeasePath);
}

function clearLeaseFile() {
  try {
    const lease = readLeaseFile();
    if (lease && lease.pid === process.pid) fs.unlinkSync(leasePath());
  } catch {
    // Idempotent cleanup.
  }
}

function clearAllLeaseFiles() {
  clearOwnerLeaseHeartbeat();
  clearLeaseFile();
  clearOwnerLeaseFile();
}

